import { useEffect, useState } from "react";
import "./styles.css"
import { useLocation } from "react-router-dom";
function Mainweatherpage() {
  let location = useLocation()
    const API_KEY_WEATHER = process.env.REACT_APP_API_KEY_WEATHER
    let [cityinput, changeinput] = useState("")
    let [dataafterclick, changedata] = useState(null)
    let [loadflag, changeflag] = useState(false)
    function function1(e) { 
        changeinput(e.target.value)
    }
    useEffect(() => {
      console.log(location.state)
      async function weatherdatafromback() {
        let arrback = await fetch("http://localhost:5000/accesstosession", {
            method: "GET",
            headers: {"Content-Type":"application/json"},
            credentials: "include",
        })
         let temporary =  await arrback.json()
         changedata(temporary.sessionback)
         changeflag(true)

      }
      weatherdatafromback()
    }, [location.state])
    async function apicall() {
        try {
        let weatherdata  = await fetch(`https://api.openweathermap.org/data/2.5/weather?q=${cityinput[0].toUpperCase() + cityinput.slice(1)}&appid=${API_KEY_WEATHER}&units=metric`)
        let updatedweather = await weatherdata.json()
        let alldata2 = {maindata: updatedweather.main, city: updatedweather.name, weathertype: updatedweather.weather[0]}
        let arrback = await fetch("http://localhost:5000/weathersession", {
            method: "POST",
            headers: {"Content-Type":"application/json"},
            credentials: "include",
            body: JSON.stringify({citysessionback: alldata2})
        })
         let temporary =  await arrback.json()
         changedata(temporary)
         console.log(dataafterclick)
        } catch(err) {
            console.log(err)
        }
    }
if(loadflag == true) {
return<>
  <div className="controls">
    <input
      value={cityinput}
      onChange={(e) => function1(e)}
      type="text"
      placeholder="Enter city (e.g. London)"
    />
    <button onClick={() => apicall()}>Look at the weather</button>  
  </div>
<div>
  <div className="weather-main">
    <div className="city">
      <p className="label">My location</p>
      <p className="name">{dataafterclick ? dataafterclick.city :  "—"}</p>
    </div>
  <div className="temp">
      <div className="degrees">{dataafterclick?.maindata?.temp ?  dataafterclick.maindata.temp : "—"}°</div>
      <div className="type">{dataafterclick?.weathertype?.main ?  dataafterclick.weathertype.main : "—"}</div>
    </div>
  </div>

  <div className="stats" role="list" aria-label="Weather details">
    <div className="stat" role="listitem">
      <div className="val">{dataafterclick?.maindata?.temp_max ? Math.floor(dataafterclick.maindata.temp_max) : "—"}°</div>
      <div className="k">High</div>
    </div>
    <div className="stat" role="listitem">
      <div className="val">{dataafterclick?.maindata?.temp_min ? Math.floor(dataafterclick.maindata.temp_min) : "—"}°</div>
      <div className="k">Low</div>
    </div>
    <div className="stat" role="listitem">
      <div className="val">{dataafterclick?.maindata?.feels_like ? Math.floor(dataafterclick.maindata.feels_like) : "—"}°</div>
      <div className="k">Feels like</div>
    </div>
    <div className="stat" role="listitem">
      <div className="val">{dataafterclick?.maindata?.humidity ? dataafterclick.maindata.humidity : "—"}%</div>
      <div className="k">Humidity</div>
    </div>
  </div>

  <div className="weather-footer">
    <span>Data provided by your API</span>
    <span style={{opacity:0.85}}>Updated just now</span>
  </div>
    </div>
  
    </>
}}
export default Mainweatherpage
